/**
 * QuickAdd Macro: Capture to Basic Memory
 * This script captures daily insights and task patterns to Basic Memory
 * 
 * Setup:
 * 1. Install QuickAdd plugin
 * 2. Create a new Macro called "Capture to Basic Memory"
 * 3. Add this script to the macro
 * 4. Assign a hotkey (recommended: Cmd+Shift+M)
 */

module.exports = async (params) => {
    const { app, quickAddApi } = params;
    const { exec } = require('child_process');
    const { promisify } = require('util');
    const execAsync = promisify(exec);

    // Get the active file
    const activeFile = app.workspace.getActiveFile();
    if (!activeFile) {
        new Notice("No active file to capture");
        return;
    }

    // Determine capture type based on file path
    const filePath = activeFile.path;
    let captureType = "note";
    let folder = "life-os/general";

    if (filePath.includes("📅 Daily")) {
        captureType = "daily-insight";
        folder = "life-os/daily-insights";
    } else if (filePath.includes("🎯 Tasks")) {
        captureType = "task-pattern";
        folder = "life-os/task-patterns";
    } else if (filePath.includes("📊 Dashboard/Weekly")) {
        captureType = "weekly-review";
        folder = "life-os/weekly-reviews";
    }

    // Get file content
    const content = await app.vault.read(activeFile);

    // Extract relevant sections based on type
    let extractedContent = "";
    let title = "";

    switch (captureType) {
        case "daily-insight":
            title = `Daily Insights ${activeFile.basename}`;
            extractedContent = extractDailyInsights(content);
            break;

        case "task-pattern":
            title = `Task Pattern - ${activeFile.basename}`;
            extractedContent = extractTaskPattern(content);
            break;

        case "weekly-review":
            title = `Weekly Review ${activeFile.basename}`;
            extractedContent = extractWeeklyReview(content);
            break;

        default:
            title = activeFile.basename;
            extractedContent = content;
    }

    // Prepare the Basic Memory command
    const escapedContent = extractedContent.replace(/"/g, '\\"').replace(/\n/g, '\\n');
    const command = `basic-memory tool write-note --title "${title}" --folder "${folder}" --content "${escapedContent}"`;

    try {
        // Execute the command
        const { stdout, stderr } = await execAsync(command);

        if (stderr) {
            console.error('Error:', stderr);
            new Notice(`Error capturing to Basic Memory: ${stderr}`);
        } else {
            new Notice(`✅ Captured to Basic Memory: ${title}`);
            console.log('Basic Memory Response:', stdout);

            // Optionally, add a note to the file indicating it was captured
            const timestamp = new Date().toISOString();
            const captureNote = `\n\n---\n*Captured to Basic Memory at ${timestamp}*`;

            // Only add if not already present
            if (!content.includes("Captured to Basic Memory")) {
                await app.vault.modify(activeFile, content + captureNote);
            }
        }
    } catch (error) {
        console.error('Failed to capture to Basic Memory:', error);
        new Notice(`Failed to capture: ${error.message}`);
    }
};

// Helper function to extract daily insights
function extractDailyInsights(content) {
    const sections = {
        accomplishments: extractSection(content, "Wins & Accomplishments", "🎉"),
        insights: extractSection(content, "Key Insights", "💡"),
        challenges: extractSection(content, "Challenges", "🚧"),
        gratitude: extractSection(content, "Gratitude", "🙏"),
        tomorrow: extractSection(content, "Tomorrow", "🔄")
    };

    let extracted = "# Daily Insights\n\n";

    if (sections.accomplishments) {
        extracted += `## Accomplishments\n${sections.accomplishments}\n\n`;
    }
    if (sections.insights) {
        extracted += `## Key Insights\n${sections.insights}\n\n`;
    }
    if (sections.challenges) {
        extracted += `## Challenges\n${sections.challenges}\n\n`;
    }
    if (sections.tomorrow) {
        extracted += `## Tomorrow's Focus\n${sections.tomorrow}\n\n`;
    }

    // Extract metrics if present
    const metricsMatch = content.match(/\| Metric \| Target \| Actual \| Notes \|[\s\S]*?\n\n/);
    if (metricsMatch) {
        extracted += `## Metrics\n${metricsMatch[0]}\n\n`;
    }

    return extracted;
}

// Helper function to extract task pattern
function extractTaskPattern(content) {
    const frontmatter = extractFrontmatter(content);
    const mainContent = content.replace(/---[\s\S]*?---/, '').trim();

    let extracted = "# Task Pattern\n\n";

    if (frontmatter.priority) {
        extracted += `**Priority**: ${frontmatter.priority}\n`;
    }
    if (frontmatter.status) {
        extracted += `**Status**: ${frontmatter.status}\n`;
    }
    if (frontmatter.project) {
        extracted += `**Project**: ${frontmatter.project}\n`;
    }

    extracted += "\n" + mainContent;

    return extracted;
}

// Helper function to extract weekly review
function extractWeeklyReview(content) {
    const sections = {
        accomplishments: extractSection(content, "Week's Accomplishments", "🎯"),
        metrics: extractSection(content, "Metrics", "📊"),
        lessons: extractSection(content, "Lessons Learned", "📚"),
        nextWeek: extractSection(content, "Next Week", "🔮")
    };

    let extracted = "# Weekly Review\n\n";

    Object.entries(sections).forEach(([key, value]) => {
        if (value) {
            const title = key.charAt(0).toUpperCase() + key.slice(1).replace(/([A-Z])/g, ' $1');
            extracted += `## ${title}\n${value}\n\n`;
        }
    });

    return extracted;
}

// Helper function to extract a section from content
function extractSection(content, sectionName, emoji = "") {
    // Try multiple patterns to find the section
    const patterns = [
        new RegExp(`###?\\s*${emoji}?\\s*${sectionName}[\\s\\S]*?(?=###|##|$)`, 'i'),
        new RegExp(`\\*\\*${sectionName}\\*\\*[\\s\\S]*?(?=\\*\\*|##|$)`, 'i'),
        new RegExp(`${sectionName}:[\\s\\S]*?(?=\\n\\n|$)`, 'i')
    ];

    for (const pattern of patterns) {
        const match = content.match(pattern);
        if (match) {
            return match[0]
                .replace(new RegExp(`###?\\s*${emoji}?\\s*${sectionName}`, 'i'), '')
                .replace(new RegExp(`\\*\\*${sectionName}\\*\\*`, 'i'), '')
                .replace(new RegExp(`${sectionName}:`, 'i'), '')
                .trim();
        }
    }

    return null;
}

// Helper function to extract frontmatter
function extractFrontmatter(content) {
    const match = content.match(/---\n([\s\S]*?)\n---/);
    if (!match) return {};

    const frontmatter = {};
    const lines = match[1].split('\n');

    lines.forEach(line => {
        const [key, ...valueParts] = line.split(':');
        if (key && valueParts.length > 0) {
            frontmatter[key.trim()] = valueParts.join(':').trim();
        }
    });

    return frontmatter;
}

